fields.collector:
$auditIds=8003,8006,8020,8021,8024,8028,8038
$blockIds=8004,8007,8022,8029,8040
$allIds=$auditIds+$blockIds|Sort-Object -Unique
$t=(Get-Date).AddHours(-24)
$logs=@('Microsoft-Windows-AppLocker/EXE and DLL','Microsoft-Windows-AppLocker/MSI and Script','Microsoft-Windows-AppLocker/Packaged app-Execution')
$raw=foreach($log in $logs){
 Get-WinEvent -FilterHashtable @{LogName=$log;Id=$allIds;StartTime=$t} -EA SilentlyContinue|%{
  $d=([xml]$_.ToXml()).Event.UserData.RuleAndFileData
  $rp=[string]$d.FilePath
  $fp=$rp -replace '%OSDRIVE%',$env:SystemDrive
  [pscustomobject]@{E=$_;L=$log;D=$d;R=$rp;F=$fp}
 }
}
$pc=@{}
$raw|%{if($_.R){$pc[$_.R]=[int]$pc[$_.R]+1}}
$events=foreach($e in $raw){
 $ev=$e.E;$d=$e.D;$fp=$e.F
 $fn=if($fp){Split-Path -Leaf $fp}
 $rc=switch -Wildcard($e.L){'*EXE*'{'Exe/Dll'}'*MSI*'{'Msi/Script'}'*Pack*'{'PackagedApp'}default{$e.L}}
 $et=if($blockIds -contains $ev.Id){'Denied'}else{'Audited'}
 $uc=[int]$pc[$e.R]
 $fd=$null;$fv=$null;$pn=$null;$fl=$null;$fh=[string]$d.FileHash
 $pu=$null;$fu=$null;$sg=$null;$pr=$null;$hr=$null;$lr=$null
 if($fp -and (Test-Path $fp -EA SilentlyContinue)){
  try{$vi=(Get-ItemProperty $fp -EA SilentlyContinue).VersionInfo;$fd=if($vi.FileDescription){$vi.FileDescription}else{$fn};$fv=if($vi.FileVersion){$vi.FileVersion}else{'Unavailable'};$pn=if($vi.ProductName){$vi.ProductName}else{$fd}}catch{}
  try{$h=Get-FileHash $fp -Algorithm SHA256 -EA SilentlyContinue;if($h){$fh=$h.Hash}}catch{if($_.Exception.Message -match 'Denied'){$fh='Access denied'}}
  try{$fl=(Get-Item $fp -EA SilentlyContinue).Length}catch{}
  try{$ai=Get-AppLockerFileInformation $fp -EA SilentlyContinue;$pbn=$ai.Publisher.PublisherName;if([string]::IsNullOrEmpty($pbn)){$pu='Unsigned';$fu='N/A';$sg='No'}else{$pu=(($pbn -split ',')[0]).TrimStart('O=');$fu=[string]$ai.Publisher;$sg='Yes'}}catch{}
  if($fu -and $fu -ne 'N/A'){try{$pr=[string]($ai|New-AppLockerPolicy -RuleType Publisher -User Everyone -RuleNamePrefix $pn -XML -EA SilentlyContinue)}catch{$pr='Unsigned Application'}}else{$pr='Unsigned Application'}
  try{$hr=[string]($ai|New-AppLockerPolicy -RuleType Hash -User Everyone -RuleNamePrefix $pn -XML -EA SilentlyContinue)}catch{}
  try{$lr=[string]($ai|New-AppLockerPolicy -RuleType Path -User Everyone -RuleNamePrefix $pn -XML -EA SilentlyContinue)}catch{}
 }
 [pscustomobject]@{
  EventTimeUtc=$ev.TimeCreated.ToUniversalTime().ToString('o')
  EventRecordId=[long]$ev.RecordId
  EventId=[int]$ev.Id
  EventType=$et
  EventMessage=$ev.Message
  RuleCollection=$rc
  PolicyName=[string]$d.PolicyName
  RuleName=[string]$d.RuleName
  FilePath=$fp
  FileName=$fn
  FileHash=$fh
  FileDescription=$fd
  FileVersion=$fv
  ProductName=$pn
  FileLength=$fl
  Publisher=$pu
  FullPublisher=$fu
  FileUseCount=$uc
  AppLockerPublisherRule=$pr
  AppLockerHashRule=$hr
  AppLockerPathRule=$lr
  Signed=$sg
  TargetUser=[string]$d.TargetUser
 }
}
@($events)
